	_appliedScoreSteps = /* @__PURE__ */ new Map();
	_appliedScoreStepsByValue = /* @__PURE__ */ new Map();
	_notesByValue = /* @__PURE__ */ new Map();
	_beatSteps = /* @__PURE__ */ new Map();
