/**
* Lists the different states of the player
* @public
*/
var PlayerState = /* @__PURE__ */ function(PlayerState) {
	/**
	* Player is paused
	*/
	PlayerState[PlayerState["Paused"] = 0] = "Paused";
	/**
	* Player is playing
	*/
	PlayerState[PlayerState["Playing"] = 1] = "Playing";
	return PlayerState;
}({});
