			this.attack = other.attack;
			this.hold = other.hold;
			this.decay = other.decay;
			this.sustain = other.sustain;
			this.release = other.release;
			this.keynumToHold = other.keynumToHold;
			this.keynumToDecay = other.keynumToDecay;
