			y1 = cy + smufl.tabBendStaffPadding;
			if (secondPt.offset === firstPt.offset) y1 += noteRenderer.getNoteY(note.beat.maxStringNote, NoteYPosition.Top) - noteNumberAndLinePaddingY;
