			this._paintBendLineSlurText(canvas, x1, y1, x2, y2, note, res.graceFont);
			this._paintBendLineValueText(canvas, y1, x2, y2 - smufl.tabBendLabelPadding, firstPt, secondPt, res.tablatureFont);
